    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: linear-gradient(135deg, #0a0e27 0%, #1a0a2e 50%, #16213e 100%);
            color: #e0e0e0;
            line-height: 1.6;
            min-height: 100vh;
        }

        /* 顶部导航栏 */
        .navbar {
            background: rgba(10, 14, 39, 0.95);
            border-bottom: 2px solid #6366f1;
            padding: 1rem 2rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            position: sticky;
            top: 0;
            z-index: 1000;
            box-shadow: 0 4px 20px rgba(99, 102, 241, 0.2);
        }

        .logo {
            font-size: 1.8rem;
            font-weight: bold;
            background: linear-gradient(135deg, #6366f1, #a855f7);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
            letter-spacing: 2px;
        }

        .nav-menu {
            display: flex;
            gap: 2rem;
            list-style: none;
        }

        .nav-menu a {
            color: #e0e0e0;
            text-decoration: none;
            padding: 0.5rem 1rem;
            border-radius: 4px;
            transition: all 0.3s;
        }

        .nav-menu a:hover {
            color: #a855f7;
            background: rgba(168, 85, 247, 0.1);
        }

        .container {
            max-width: 1400px;
            margin: 0 auto;
            padding: 2rem;
        }

        /* 主内容区 */
        .main-content {
            display: grid;
            grid-template-columns: 1fr 2fr 1fr;
            gap: 2rem;
            margin-bottom: 2rem;
        }

        /* 英雄选择面板 */
        .heroes-panel {
            background: rgba(26, 10, 46, 0.6);
            border: 1px solid #6366f1;
            border-radius: 12px;
            padding: 1.5rem;
            backdrop-filter: blur(10px);
        }

        .panel-title {
            font-size: 1.3rem;
            color: #a855f7;
            margin-bottom: 1rem;
            border-left: 3px solid #6366f1;
            padding-left: 1rem;
        }

        .hero-list {
            display: flex;
            flex-direction: column;
            gap: 0.8rem;
        }

        .hero-item {
            background: rgba(99, 102, 241, 0.1);
            padding: 1rem;
            border-radius: 8px;
            border-left: 3px solid #6366f1;
            cursor: pointer;
            transition: all 0.3s;
        }

        .hero-item:hover {
            background: rgba(168, 85, 247, 0.15);
            transform: translateX(5px);
        }

        .hero-name {
            font-weight: bold;
            color: #a855f7;
            margin-bottom: 0.3rem;
        }

        .hero-stats {
            font-size: 0.85rem;
            color: #b0b0b0;
        }

        /* 战绩统计面板 */
        .stats-main {
            background: rgba(26, 10, 46, 0.6);
            border: 1px solid #6366f1;
            border-radius: 12px;
            padding: 2rem;
            backdrop-filter: blur(10px);
        }

